function normalizeSearchValue(value) {
  return String(value || "").trim();
}

export function findTaskById(tasks, idQuery) {
  const normalizedQuery = normalizeSearchValue(idQuery);

  if (!normalizedQuery || !Array.isArray(tasks)) {
    return null;
  }

  return tasks.find((task) => normalizeSearchValue(task.id) === normalizedQuery) || null;
}

export function findTaskByUniqueId(tasks, uniqueIdQuery) {
  const normalizedQuery = normalizeSearchValue(uniqueIdQuery);

  if (!normalizedQuery || !Array.isArray(tasks)) {
    return null;
  }

  return tasks.find((task) => normalizeSearchValue(task.uniqueId) === normalizedQuery) || null;
}

export function findTaskByPartialName(tasks, nameQuery) {
  const normalizedQuery = normalizeSearchValue(nameQuery).toLowerCase();

  if (!normalizedQuery || !Array.isArray(tasks)) {
    return null;
  }

  return tasks.find((task) => normalizeSearchValue(task.name).toLowerCase().includes(normalizedQuery)) || null;
}

export function findTasksByPartialName(tasks, nameQuery) {
  const normalizedQuery = normalizeSearchValue(nameQuery).toLowerCase();

  if (!normalizedQuery || !Array.isArray(tasks)) {
    return [];
  }

  return tasks.filter((task) => normalizeSearchValue(task.name).toLowerCase().includes(normalizedQuery));
}
