// Convert a raw value into a stable string for the shared task model.
function toDisplayValue(value) {
  if (value === null || value === undefined || value === "") {
    return "";
  }

  return String(value);
}

// Convert an ID value into a numeric value usable for sorting.
function toSortableId(value) {
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? numericValue : Number.POSITIVE_INFINITY;
}

// Count the WBS depth so host UIs can derive indentation consistently.
function getWbsIndentLevel(wbs) {
  const wbsText = String(wbs ?? "").trim();

  if (!wbsText) {
    return 0;
  }

  return (wbsText.match(/\./g) || []).length;
}

// Build a host-neutral display name that preserves the current WBS indentation convention.
function buildIndentedTaskName(name, wbs) {
  return `${" ".repeat(getWbsIndentLevel(wbs) * 3)}${name}`;
}

// Convert a normalized summary-like value into a strict boolean.
function toSummaryFlag(value) {
  return value === true;
}

// Normalize raw task rows into the shared task shape used across hosts.
export function normalizeTasks(rows) {
  if (!Array.isArray(rows)) {
    return [];
  }

  return rows
    .filter((row) => row && typeof row.name === "string" && row.name.trim() !== "")
    .map((row) => ({
      id: toDisplayValue(row.id),
      uniqueId: toDisplayValue(row.uniqueId),
      wbs: toDisplayValue(row.wbs),
      name: row.name.trim(),
      displayName: buildIndentedTaskName(row.name.trim(), row.wbs),
      isSummary: toSummaryFlag(row.summary),
      startDate: toDisplayValue(row.startDate),
      endDate: toDisplayValue(row.endDate)
    }))
    .sort((leftTask, rightTask) => toSortableId(leftTask.id) - toSortableId(rightTask.id));
}

export function createTaskIndex(tasks) {
  return new Map(
    Array.isArray(tasks)
      ? tasks.map((task) => [String(task.id), task])
      : []
  );
}
