const FIELD_NAME_ALIASES = {
  id: "id",
  "unique id": "uniqueId",
  uid: "uniqueId",
  wbs: "wbs",
  name: "name",
  nom: "name",
  "שם": "name",
  "שם פעילות": "name",
  summary: "summary",
  "ערסל": "summary",
  start: "startDate",
  "start date": "startDate",
  "date de debut": "startDate",
  finish: "endDate",
  "finish date": "endDate",
  "end date": "endDate",
  "date de fin": "endDate"
};

function isRecord(value) {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

export function normalizeFieldName(fieldName) {
  return String(fieldName)
    .replace(/^\uFEFF/, "")
    .trim()
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ")
    .toLowerCase();
}

export function getCanonicalFieldName(fieldName) {
  return FIELD_NAME_ALIASES[normalizeFieldName(fieldName)] || null;
}

export function getCanonicalTaskValue(rawTask, canonicalFieldName) {
  if (!isRecord(rawTask)) {
    return "";
  }

  const directValue = rawTask[canonicalFieldName];

  if (directValue !== undefined && directValue !== null) {
    return directValue;
  }

  const matchingEntry = Object.entries(rawTask).find(([fieldName]) => {
    return getCanonicalFieldName(fieldName) === canonicalFieldName;
  });

  return matchingEntry ? matchingEntry[1] : "";
}

function ensureTaskArray(tasks) {
  if (!Array.isArray(tasks)) {
    throw new Error("Planning data must contain a tasks array.");
  }

  return tasks;
}

function normalizeTwoDigitYear(yearText) {
  const yearValue = Number(yearText);

  if (yearText.length === 4) {
    return yearValue;
  }

  return yearValue < 70 ? 2000 + yearValue : 1900 + yearValue;
}

function isValidDateParts(year, month, day) {
  const date = new Date(Date.UTC(year, month - 1, day));

  return (
    date.getUTCFullYear() === year &&
    date.getUTCMonth() === month - 1 &&
    date.getUTCDate() === day
  );
}

function getSlashDateEvidence(value) {
  const match = String(value).trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})$/);

  if (!match) {
    return null;
  }

  const firstPart = Number(match[1]);
  const secondPart = Number(match[2]);

  if (firstPart > 12 && secondPart <= 12) {
    return "DMY";
  }

  if (secondPart > 12 && firstPart <= 12) {
    return "MDY";
  }

  if (firstPart > 12 && secondPart > 12) {
    throw new Error("A slash-formatted date contains invalid month values.");
  }

  return null;
}

export function inferSlashDateOrder(rawTasks) {
  let inferredOrder = null;

  rawTasks.forEach((rawTask) => {
    ["startDate", "endDate"].forEach((fieldName) => {
      const rawValue = getCanonicalTaskValue(rawTask, fieldName);

      if (!rawValue) {
        return;
      }

      const evidence = getSlashDateEvidence(rawValue);

      if (!evidence) {
        return;
      }

      if (inferredOrder && inferredOrder !== evidence) {
        throw new Error("The file contains conflicting slash-formatted date conventions.");
      }

      inferredOrder = evidence;
    });
  });

  return inferredOrder;
}

function normalizeIsoLikeDate(value) {
  const match = String(value).trim().match(/^(\d{4})-(\d{2})-(\d{2})/);

  if (!match) {
    return null;
  }

  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);

  if (!isValidDateParts(year, month, day)) {
    throw new Error("An ISO-like date is invalid.");
  }

  return `${match[1]}-${match[2]}-${match[3]}`;
}

function normalizeSlashDate(value, slashDateOrder) {
  const match = String(value).trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})$/);

  if (!match) {
    return null;
  }

  if (!slashDateOrder) {
    throw new Error("The file contains ambiguous slash-formatted dates and the format could not be inferred.");
  }

  const firstPart = Number(match[1]);
  const secondPart = Number(match[2]);
  const year = normalizeTwoDigitYear(match[3]);
  const day = slashDateOrder === "DMY" ? firstPart : secondPart;
  const month = slashDateOrder === "DMY" ? secondPart : firstPart;

  if (!isValidDateParts(year, month, day)) {
    throw new Error("A slash-formatted date is invalid.");
  }

  return `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

export function normalizeDateValue(value, slashDateOrder) {
  if (value === null || value === undefined || value === "") {
    return "";
  }

  const isoDate = normalizeIsoLikeDate(value);

  if (isoDate) {
    return isoDate;
  }

  const slashDate = normalizeSlashDate(value, slashDateOrder);

  if (slashDate) {
    return slashDate;
  }

  return String(value).trim();
}

function normalizeTaskValue(value) {
  if (value === null || value === undefined) {
    return "";
  }

  return String(value).trim();
}

function normalizeSummaryValue(value) {
  const normalizedValue = String(value ?? "").trim().toLowerCase();

  return normalizedValue === "1" || normalizedValue === "true" || normalizedValue === "yes";
}

export function normalizeTask(rawTask, slashDateOrder) {
  return {
    id: normalizeTaskValue(getCanonicalTaskValue(rawTask, "id")),
    uniqueId: normalizeTaskValue(getCanonicalTaskValue(rawTask, "uniqueId")),
    wbs: normalizeTaskValue(getCanonicalTaskValue(rawTask, "wbs")),
    name: normalizeTaskValue(getCanonicalTaskValue(rawTask, "name")),
    summary: normalizeSummaryValue(getCanonicalTaskValue(rawTask, "summary")),
    startDate: normalizeDateValue(getCanonicalTaskValue(rawTask, "startDate"), slashDateOrder),
    endDate: normalizeDateValue(getCanonicalTaskValue(rawTask, "endDate"), slashDateOrder)
  };
}

export function normalizeDependencyLink(rawLink) {
  return {
    predecessorId: String(rawLink?.predecessorId ?? "").trim(),
    successorId: String(rawLink?.successorId ?? "").trim(),
    type: String(rawLink?.type ?? "FS").trim() || "FS",
    lag: String(rawLink?.lag ?? "").trim(),
    lagFormat: String(rawLink?.lagFormat ?? "").trim()
  };
}

export function normalizePlanningData(parsedPlanningData) {
  const rawTasks = ensureTaskArray(parsedPlanningData?.tasks);
  const slashDateOrder = inferSlashDateOrder(rawTasks);

  return {
    tasks: rawTasks.map((rawTask) => normalizeTask(rawTask, slashDateOrder)),
    dependencyLinks: Array.isArray(parsedPlanningData?.dependencyLinks)
      ? parsedPlanningData.dependencyLinks.map(normalizeDependencyLink)
      : []
  };
}
