// Return the direct predecessor task objects for one selected task.
export function getDirectPredecessors(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  const predecessorIds = dependencyLinks
    .filter((link) => String(link.successorId) === String(taskId))
    .map((link) => String(link.predecessorId));

  return tasks.filter((task) => predecessorIds.includes(String(task.id)));
}

function normalizeRelationType(type) {
  const relationType = String(type || "").trim().toUpperCase();
  const numericTypeMap = {
    0: "FF",
    1: "FS",
    2: "SF",
    3: "SS"
  };

  if (/^\d+$/.test(relationType) && numericTypeMap[Number(relationType)]) {
    return numericTypeMap[Number(relationType)];
  }

  return relationType || "FS";
}

function getLagMetadata(lagFormat) {
  const normalizedLagFormat = Number(String(lagFormat ?? "").trim());
  const metadataByFormat = {
    3: { unit: "minute", divisor: 10, elapsed: false },
    4: { unit: "minute", divisor: 10, elapsed: true },
    5: { unit: "hour", divisor: 600, elapsed: false },
    6: { unit: "hour", divisor: 600, elapsed: true },
    7: { unit: "day", divisor: 4800, elapsed: false },
    8: { unit: "day", divisor: 4800, elapsed: true },
    9: { unit: "week", divisor: 24000, elapsed: false },
    10: { unit: "week", divisor: 24000, elapsed: true },
    11: { unit: "month", divisor: 96000, elapsed: false },
    12: { unit: "month", divisor: 96000, elapsed: true },
    19: { unit: "%", divisor: 1, elapsed: false },
    20: { unit: "%", divisor: 1, elapsed: true },
    35: { unit: "minute", divisor: 10, elapsed: false },
    36: { unit: "minute", divisor: 10, elapsed: true },
    37: { unit: "hour", divisor: 600, elapsed: false },
    38: { unit: "hour", divisor: 600, elapsed: true },
    39: { unit: "day", divisor: 4800, elapsed: false },
    40: { unit: "day", divisor: 4800, elapsed: true },
    41: { unit: "week", divisor: 24000, elapsed: false },
    42: { unit: "week", divisor: 24000, elapsed: true },
    43: { unit: "month", divisor: 96000, elapsed: false },
    44: { unit: "month", divisor: 96000, elapsed: true },
    51: { unit: "%", divisor: 1, elapsed: false },
    52: { unit: "%", divisor: 1, elapsed: true }
  };

  return metadataByFormat[normalizedLagFormat] || { unit: "day", divisor: 4800, elapsed: false };
}

function parseIsoDate(dateText) {
  const match = String(dateText || "").trim().match(/^(\d{4})-(\d{2})-(\d{2})$/);

  if (!match) {
    return null;
  }

  return new Date(Date.UTC(Number(match[1]), Number(match[2]) - 1, Number(match[3])));
}

function formatIsoDate(date) {
  if (!(date instanceof Date) || Number.isNaN(date.getTime())) {
    return "";
  }

  const year = String(date.getUTCFullYear());
  const month = String(date.getUTCMonth() + 1).padStart(2, "0");
  const day = String(date.getUTCDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function isWorkingDay(date) {
  const weekday = date.getUTCDay();
  return weekday !== 0 && weekday !== 6;
}

function addBusinessDays(date, amount) {
  const result = new Date(date.getTime());
  const step = amount >= 0 ? 1 : -1;
  let remainingDays = Math.abs(amount);

  while (remainingDays > 0) {
    result.setUTCDate(result.getUTCDate() + step);

    if (isWorkingDay(result)) {
      remainingDays -= 1;
    }
  }

  return result;
}

function applyLagToDriverDate(driverDate, lag, lagFormat) {
  const lagText = String(lag ?? "").trim();

  if (!driverDate || !lagText) {
    return driverDate;
  }

  const lagValue = Number(lagText);

  if (!Number.isFinite(lagValue) || lagValue === 0) {
    return driverDate;
  }

  const baseDate = parseIsoDate(driverDate);

  if (!baseDate) {
    return driverDate;
  }

  const lagMetadata = getLagMetadata(lagFormat);

  if (lagMetadata.unit === "%") {
    return driverDate;
  }

  const normalizedLagValue = lagValue / lagMetadata.divisor;
  const signedWholeDays = (() => {
    if (lagMetadata.unit === "day") {
      return Math.trunc(normalizedLagValue);
    }

    if (lagMetadata.unit === "week") {
      return Math.trunc(normalizedLagValue * 5);
    }

    if (lagMetadata.unit === "month") {
      return Math.trunc(normalizedLagValue * 20);
    }

    if (lagMetadata.unit === "hour") {
      return Math.trunc(normalizedLagValue / 8);
    }

    if (lagMetadata.unit === "minute") {
      return Math.trunc(normalizedLagValue / 480);
    }

    return 0;
  })();

  if (lagMetadata.elapsed) {
    const result = new Date(baseDate.getTime());

    if (lagMetadata.unit === "minute") {
      result.setUTCMinutes(result.getUTCMinutes() + normalizedLagValue);
      return formatIsoDate(result);
    }

    if (lagMetadata.unit === "hour") {
      result.setUTCHours(result.getUTCHours() + normalizedLagValue);
      return formatIsoDate(result);
    }

    if (lagMetadata.unit === "day") {
      result.setUTCDate(result.getUTCDate() + normalizedLagValue);
      return formatIsoDate(result);
    }

    if (lagMetadata.unit === "week") {
      result.setUTCDate(result.getUTCDate() + (normalizedLagValue * 7));
      return formatIsoDate(result);
    }

    if (lagMetadata.unit === "month") {
      result.setUTCMonth(result.getUTCMonth() + normalizedLagValue);
      return formatIsoDate(result);
    }

    return driverDate;
  }

  return formatIsoDate(addBusinessDays(baseDate, signedWholeDays));
}

function getNextWorkingDay(driverDate) {
  const baseDate = parseIsoDate(driverDate);

  if (!baseDate) {
    return driverDate;
  }

  return formatIsoDate(addBusinessDays(baseDate, 1));
}

function formatRelationLag(lag, lagFormat) {
  const lagText = String(lag ?? "").trim();

  if (!lagText) {
    return "";
  }

  const lagValue = Number(lagText);

  if (!Number.isFinite(lagValue)) {
    return ` + ${lagText}`;
  }

  if (lagValue === 0) {
    return "";
  }

  const lagMetadata = getLagMetadata(lagFormat);
  const unit = lagMetadata.unit;
  const absoluteValue = Math.abs(lagValue) / lagMetadata.divisor;
  const normalizedAbsoluteValue = Number.isInteger(absoluteValue)
    ? absoluteValue
    : Number(absoluteValue.toFixed(2));
  const sign = lagValue >= 0 ? "+" : "-";

  if (unit === "%") {
    return ` ${sign} ${normalizedAbsoluteValue}%`;
  }

  return ` ${sign} ${normalizedAbsoluteValue} ${unit}${normalizedAbsoluteValue === 1 ? "" : "s"}`;
}

function formatRelationLabel(link) {
  const relationType = normalizeRelationType(link.type);
  return `${relationType}${formatRelationLag(link.lag, link.lagFormat)}`;
}

function findTaskByTaskId(taskId, tasks) {
  return tasks.find((candidateTask) => String(candidateTask.id) === String(taskId)) || null;
}

function getStartConstraintDriverDate(link, tasks) {
  if (!link) {
    return "";
  }

  const predecessorTask = findTaskByTaskId(link.predecessorId, tasks);

  if (!predecessorTask) {
    return "";
  }

  const relationType = normalizeRelationType(link.type);

  if (relationType === "FS") {
    const lagMetadata = getLagMetadata(link.lagFormat);
    const finishDriverDate = applyLagToDriverDate(predecessorTask.endDate || "", link.lag, link.lagFormat);

    if (lagMetadata.elapsed) {
      return finishDriverDate;
    }

    return getNextWorkingDay(finishDriverDate);
  }

  if (relationType === "SS") {
    return applyLagToDriverDate(predecessorTask.startDate || "", link.lag, link.lagFormat);
  }

  return "";
}

export function getDirectPredecessorRelations(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  return dependencyLinks
    .filter((link) => String(link.successorId) === String(taskId))
    .map((link) => {
      const task = tasks.find((candidateTask) => String(candidateTask.id) === String(link.predecessorId));

      if (!task) {
        return null;
      }

      return {
        task,
        relationLabel: formatRelationLabel(link)
      };
    })
    .filter(Boolean);
}

