export function getSecondPredecessorRelations(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  const directPredecessorIds = new Set(
    dependencyLinks
      .filter((link) => String(link.successorId) === String(taskId))
      .map((link) => String(link.predecessorId))
  );

  return dependencyLinks
    .filter((link) => directPredecessorIds.has(String(link.successorId)))
    .map((link) => {
      const task = findTaskByTaskId(link.predecessorId, tasks);

      if (!task) {
        return null;
      }

      return {
        task,
        childTaskId: String(link.successorId),
        relationLabel: formatRelationLabel(link)
      };
    })
    .filter(Boolean);
}

export function getSecondSuccessorRelations(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  const directSuccessorIds = new Set(
    dependencyLinks
      .filter((link) => String(link.predecessorId) === String(taskId))
      .map((link) => String(link.successorId))
  );

  return dependencyLinks
    .filter((link) => directSuccessorIds.has(String(link.predecessorId)))
    .map((link) => {
      const task = findTaskByTaskId(link.successorId, tasks);

      if (!task) {
        return null;
      }

      return {
        task,
        parentTaskId: String(link.predecessorId),
        relationLabel: formatRelationLabel(link)
      };
    })
    .filter(Boolean);
}

export function getActiveStartConstraintTaskIds(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  const candidateLinks = dependencyLinks
    .filter((link) => String(link.successorId) === String(taskId))
    .map((link) => ({
      link,
      driverDate: getStartConstraintDriverDate(link, tasks)
    }))
    .filter((candidate) => candidate.driverDate);

  if (candidateLinks.length === 0) {
    return [];
  }

  const activeDriverDate = candidateLinks
    .map((candidate) => candidate.driverDate)
    .sort()
    .at(-1);

  return candidateLinks
    .filter((candidate) => candidate.driverDate === activeDriverDate)
    .map((candidate) => String(candidate.link.predecessorId));
}

export function getConstrainedSuccessorTaskIds(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  return dependencyLinks
    .filter((link) => String(link.predecessorId) === String(taskId))
    .filter((link) => {
      const selectedDriverDate = getStartConstraintDriverDate(link, tasks);

      if (!selectedDriverDate) {
        return false;
      }

      const successorCandidateLinks = dependencyLinks
        .filter((candidateLink) => String(candidateLink.successorId) === String(link.successorId))
        .map((candidateLink) => getStartConstraintDriverDate(candidateLink, tasks))
        .filter(Boolean);

      if (successorCandidateLinks.length === 0) {
        return false;
      }

      const activeDriverDate = successorCandidateLinks.sort().at(-1);
      return selectedDriverDate === activeDriverDate;
    })
    .map((link) => String(link.successorId));
}

export function getSecondLevelActivePredecessorTaskIds(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  const directPredecessorIds = dependencyLinks
    .filter((link) => String(link.successorId) === String(taskId))
    .map((link) => String(link.predecessorId));

  return [...new Set(
    directPredecessorIds.flatMap((directPredecessorId) => {
      return getActiveStartConstraintTaskIds(directPredecessorId, tasks, dependencyLinks);
    })
  )];
}

export function getSecondLevelConstrainedSuccessorTaskIds(taskId, tasks, dependencyLinks) {
  if (!taskId || !Array.isArray(tasks) || !Array.isArray(dependencyLinks)) {
    return [];
  }

  const directSuccessorIds = dependencyLinks
    .filter((link) => String(link.predecessorId) === String(taskId))
    .map((link) => String(link.successorId));

  return [...new Set(
    directSuccessorIds.flatMap((directSuccessorId) => {
      return getConstrainedSuccessorTaskIds(directSuccessorId, tasks, dependencyLinks);
    })
  )];
}

export function formatDependencyRelationLabel(link) {
  return formatRelationLabel(link);
}
